BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?subpkg ?subpkgName ?linkPred WHERE {
  {
    ?apsPkg vocab:NamedElement_name ?apsName .
    FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("Conceptual Design")) &&
           CONTAINS(LCASE(STR(?apsName)), LCASE("APS")))
    BIND(?apsPkg as ?candidate)
  }
  ?candidate ?linkPred ?subpkg .
  ?subpkg rdf:type vocab:package .
  OPTIONAL { ?subpkg vocab:NamedElement_name ?subpkgName }
  FILTER(?linkPred IN (vocab:Element_ownedElement, vocab:Package_nestedPackage, vocab:Package_packagedElement, vocab:Element_ownedElement+))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?apsPkg ?apsName ?subpkg ?subpkgName WHERE {
  ?apsPkg rdf:type vocab:package .
  ?apsPkg vocab:NamedElement_name ?apsName .
  FILTER(CONTAINS(LCASE(STR(?apsName)), LCASE("APS")) &&
         CONTAINS(LCASE(STR(?apsName)), LCASE("Conceptual Design")))

  {
    ?apsPkg vocab:Element_ownedElement+ ?subpkg .
  } UNION {
    ?apsPkg vocab:Package_nestedPackage ?subpkg .
  } UNION {
    ?apsPkg vocab:Package_packagedElement ?subpkg .
  }

  ?subpkg rdf:type vocab:package .
  OPTIONAL { ?subpkg vocab:NamedElement_name ?subpkgName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?subpkg ?subpkgName ?apsPkg ?apsName ?rel WHERE {
  VALUES ?apsPkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Conceptual%20Design>
  }
  ?apsPkg vocab:NamedElement_name ?apsName .

  ?subpkg rdf:type vocab:package .
  OPTIONAL { ?subpkg vocab:NamedElement_name ?subpkgName . }

  {
    ?subpkg vocab:Package_owningPackage ?apsPkg .
    BIND(vocab:Package_owningPackage as ?rel)
  } UNION {
    ?apsPkg vocab:Element_ownedElement ?subpkg .
    BIND(vocab:Element_ownedElement as ?rel)
  } UNION {
    ?apsPkg vocab:Package_packagedElement ?subpkg .
    BIND(vocab:Package_packagedElement as ?rel)
  } UNION {
    ?apsPkg vocab:Package_nestedPackage ?subpkg .
    BIND(vocab:Package_nestedPackage as ?rel)
  }
}
ORDER BY ?subpkgName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName WHERE {
  VALUES ?apsPkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS%20Conceptual%20Design>
  }

  ?apsPkg vocab:Element_ownedElement+ ?child .
  ?child rdf:type ?childType .

  OPTIONAL { ?child vocab:NamedElement_name ?childName . }

  FILTER(STRSTARTS(LCASE(STR(?childType)), LCASE("http://api.koneksys.com/cameo/vocab/package")) ||
         CONTAINS(LCASE(STR(?childName)), LCASE("package")) ||
         CONTAINS(LCASE(STR(?childName)), LCASE("design"))
  )
}
LIMIT 25
